gIM(){return"\u06af\u06d5\u06cc\u0634\u062a\u0646 \u0628\u06c6 \u062c\u06cc\u062f\u06d5\u060c \u0628\u06d5\u0631\u06ce\u0648\u06d5\u0628\u06d5\u0631\u06d5\u06a9\u06d5\u062a \u0644\u06d5\u0648\u06ce \u0686\u0627\u0648\u06d5\u0695\u0648\u0627\u0646\u062a \u062f\u06d5\u0628\u06ce\u062a\u060c \u0648 \u062f\u06d5\u06af\u0648\u0627\u0632\u0631\u06ce\u06cc\u062a\u06d5\u0648\u06d5 \u0628\u06c6 \u0647\u06c6\u062a\u06ce\u0644\u06d5\u06a9\u06d5\u062a \u0644\u06d5\u062a\u06d5\u0646\u06cc\u0634\u062a \u062d\u06d5\u0631\u06d5\u0645."},
